 1	import type { FC, FormEvent } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import {
 5	  Alert,
 6	  Checkbox,
 7	  DescriptionList,
 8	  DescriptionListDescription,
 9	  DescriptionListGroup,
10	  DescriptionListTerm,
11	  Flex,
12	  FlexItem,
13	} from '@patternfly/react-core';
14	
15	/**
16	 * Verify the certificate. Logic and UI based on the component used in the standalone MTV UI.
17	 * @link https://github.com/kubev2v/forklift-ui/blob/c347020d3162b891636c3109e426343911b6c498/pkg/web/src/app/Providers/components/AddEditProviderModal/AddEditProviderModal.tsx#L399
18	 */
19	type VerifyCertificateProps = {
20	  thumbprint: string;
21	  issuer: string;
22	  validTo: Date;
23	  hasThumbprintChanged: boolean;
24	  isTrusted: boolean;
25	  setIsTrusted: (flag: boolean) => void;
26	};
27	
28	const VerifyCertificate: FC<VerifyCertificateProps> = ({
29	  hasThumbprintChanged,
30	  issuer,
31	  isTrusted,
32	  setIsTrusted,
33	  thumbprint,
34	  validTo,
35	}) => {
36	  const { t } = useForkliftTranslation();
37	
38	  const onChange: (checked: boolean, event: FormEvent<HTMLInputElement>) => void = (checked) => {
39	    setIsTrusted(checked);
40	  };
41	
42	  return (
43	    <>
44	      {hasThumbprintChanged && (
45	        <Alert variant="warning" isInline title={t('Certificate change detected')}>
46	          {t(
47	            'The current certificate does not match the certificate fetched from URL. Manually validate the fingerprint before proceeding.',
48	          )}
49	        </Alert>
50	      )}
51	      <Flex direction={{ default: 'column' }}>
52	        <FlexItem>
53	          <DescriptionList>
54	            <DescriptionListGroup>
55	              <DescriptionListTerm>{t('Issuer')}</DescriptionListTerm>
56	              <DescriptionListDescription id="issuer">{issuer}</DescriptionListDescription>
57	            </DescriptionListGroup>
58	            <DescriptionListGroup>
59	              <DescriptionListTerm>{t('SHA-1 fingerprint')}</DescriptionListTerm>
60	              <DescriptionListDescription id="fingerprint">{thumbprint}</DescriptionListDescription>
61	            </DescriptionListGroup>
62	            <DescriptionListGroup>
63	              <DescriptionListTerm>{t('Expiration date')}</DescriptionListTerm>
64	              <DescriptionListDescription id="expiration">
65	                {validTo?.toUTCString() ?? ''}
66	              </DescriptionListDescription>
67	            </DescriptionListGroup>
68	          </DescriptionList>
69	        </FlexItem>
70	        <FlexItem>
71	          <Checkbox
72	            label={t('I trust the authenticity of this certificate')}
73	            id="certificate-check"
74	            name="certificateCheck"
75	            isChecked={isTrusted}
76	            onChange={(event, value) => {
77	              onChange(value, event);
78	            }}
79	          />
80	        </FlexItem>
81	      </Flex>
82	    </>
83	  );
84	};
85	
86	export default VerifyCertificate;

